// src/pages/Attendance/AttendanceCalendarPage.js
import React, { useState, useEffect } from 'react';
import { attendanceAPI } from '../../api/services';
import { Badge } from '../../components/common';

const STATUS_COLORS = {
  Present: 'var(--green)',  Absent: 'var(--red)',
  Late:    'var(--gold)',   Leave:  'var(--amber)',
  Holiday: 'var(--purple)', Weekend:'var(--text-muted)',
};

export default function AttendanceCalendarPage() {
  const [month,   setMonth]   = useState(new Date());
  const [calData, setCalData] = useState([]);
  const [loading, setLoading] = useState(true);

  const year = month.getFullYear();
  const mon  = month.getMonth();

  useEffect(() => {
    setLoading(true);
    attendanceAPI.getCalendarMe({ year, month: mon + 1 })
      .then(res => {
        const p = res.data?.data || res.data;
        setCalData(Array.isArray(p) ? p : p?.records || p?.attendances || []);
      })
      .catch(() => {})
      .finally(() => setLoading(false));
  }, [year, mon]);

  const first = new Date(year, mon, 1).getDay();
  const days  = new Date(year, mon + 1, 0).getDate();

  const getDay = (d) => calData.find(r => {
    const rd = new Date(r.AttendanceDate || r.attendanceDate || r.date);
    return rd.getDate() === d && rd.getMonth() === mon && rd.getFullYear() === year;
  });

  return (
    <>
      <div className="page-header">
        <h1>Attendance Calendar</h1>
        <p>Your monthly attendance overview</p>
      </div>

      <div className="card">
        {/* Month nav */}
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 20 }}>
          <button className="btn btn-secondary btn-sm" onClick={() => setMonth(new Date(year, mon - 1, 1))}>← Prev</button>
          <span style={{ fontFamily: 'var(--font-display)', fontWeight: 700, fontSize: '1.1rem' }}>
            {month.toLocaleDateString('en-US', { month: 'long', year: 'numeric' })}
          </span>
          <button className="btn btn-secondary btn-sm" onClick={() => setMonth(new Date(year, mon + 1, 1))}>Next →</button>
        </div>

        {/* Day headers */}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7,1fr)', gap: 6, marginBottom: 8 }}>
          {['Sun','Mon','Tue','Wed','Thu','Fri','Sat'].map(d => (
            <div key={d} style={{ textAlign: 'center', fontSize: '0.72rem', fontWeight: 700, color: 'var(--text-muted)', padding: '4px 0' }}>{d}</div>
          ))}
        </div>

        {/* Day cells */}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7,1fr)', gap: 6 }}>
          {Array.from({ length: first }).map((_, i) => <div key={`e${i}`} />)}
          {Array.from({ length: days }).map((_, i) => {
            const d      = i + 1;
            const rec    = getDay(d);
            const status = rec?.Status || rec?.status || rec?.attendanceStatus;
            const color  = STATUS_COLORS[status] || 'transparent';
            const isToday = new Date().getDate() === d && new Date().getMonth() === mon && new Date().getFullYear() === year;
            const checkIn  = rec?.CheckInTime  || rec?.checkInTime;
            const checkOut = rec?.CheckOutTime || rec?.checkOutTime;

            return (
              <div key={d} style={{
                minHeight: 70, padding: '6px 8px',
                borderRadius: 'var(--radius-md)',
                background: isToday ? 'var(--gold-glow)' : rec ? `${color}12` : 'var(--bg-elevated)',
                border: `1px solid ${isToday ? 'var(--gold)' : rec ? `${color}40` : 'var(--border)'}`,
              }}>
                <div style={{ fontSize: '0.8rem', fontWeight: isToday ? 700 : 400, color: isToday ? 'var(--gold)' : 'var(--text-secondary)', marginBottom: 4 }}>{d}</div>
                {status && (
                  <div style={{ fontSize: '0.68rem', fontWeight: 600, color, marginBottom: 2 }}>{status}</div>
                )}
                {checkIn && (
                  <div style={{ fontSize: '0.65rem', color: 'var(--text-muted)' }}>
                    {new Date(checkIn).toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' })}
                  </div>
                )}
              </div>
            );
          })}
        </div>

        {/* Legend */}
        <div style={{ display: 'flex', gap: 14, flexWrap: 'wrap', marginTop: 20, paddingTop: 14, borderTop: '1px solid var(--border)' }}>
          {Object.entries(STATUS_COLORS).map(([k, v]) => (
            <div key={k} style={{ display: 'flex', alignItems: 'center', gap: 5, fontSize: '0.75rem', color: 'var(--text-secondary)' }}>
              <div style={{ width: 10, height: 10, borderRadius: 3, background: v }} />
              {k}
            </div>
          ))}
        </div>
      </div>
    </>
  );
}
